import React, { useEffect, useState, useRef, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { io } from 'socket.io-client';
import { useAuth } from '../context/AuthContext';
import { apiCall } from '../services/api';
import ChatBox from '../components/ChatBox';

const SOCKET_URL = process.env.REACT_APP_SOCKET_URL || 'http://localhost:5000';

// Deterministic color from a string (for member avatars)
const avatarColor = (str = '') => {
    const colors = [
        'from-violet-500 to-purple-600',
        'from-blue-500 to-indigo-600',
        'from-emerald-500 to-teal-600',
        'from-rose-500 to-pink-600',
        'from-amber-500 to-orange-600',
        'from-cyan-500 to-sky-600',
    ];
    let hash = 0;
    for (let i = 0; i < str.length; i++) hash = str.charCodeAt(i) + ((hash << 5) - hash);
    return colors[Math.abs(hash) % colors.length];
};

export default function GroupRoomPage() {
    const { id: groupId } = useParams();
    const { user, token } = useAuth();
    const navigate = useNavigate();

    const [group, setGroup] = useState(null);
    const [messages, setMessages] = useState([]);
    const [loading, setLoading] = useState(true);
    const [isConnected, setIsConnected] = useState(false);
    const socketRef = useRef(null);

    const goBack = useCallback(() => navigate('/groups'), [navigate]);

    useEffect(() => {
        let socket;

        const init = async () => {
            try {
                const [groupRes, msgRes] = await Promise.all([
                    apiCall(`/groups/${groupId}`),
                    apiCall(`/groups/${groupId}/messages`)
                ]);
                setGroup(groupRes.data);
                setMessages(msgRes.data);
            } catch (err) {
                console.error('Failed to load group:', err);
                navigate('/groups');
                return;
            } finally {
                setLoading(false);
            }

            socket = io(SOCKET_URL, { auth: { token } });
            socketRef.current = socket;

            socket.on('connect', () => {
                setIsConnected(true);
                socket.emit('joinGroup', { groupId });
            });
            socket.on('disconnect', () => setIsConnected(false));

            socket.on('newMessage', (msg) => {
                setMessages((prev) => [...prev, msg]);
            });

            socket.on('pollUpdated', (updatedPoll) => {
                setMessages((prev) =>
                    prev.map((m) =>
                        m.pollId?._id === updatedPoll._id ? { ...m, pollId: updatedPoll } : m
                    )
                );
            });

            socket.on('error', (err) => console.error('Socket error:', err.message));
        };

        if (token) init();

        return () => {
            socket?.disconnect();
        };
    }, [groupId, token, navigate]);

    // ── Loading screen ───────────────────────────────────────────────────────────
    if (loading) {
        return (
            <div className="flex flex-col items-center justify-center h-screen bg-gray-50">
                <div className="w-12 h-12 rounded-full border-4 border-gray-200 border-t-blue-500 animate-spin mb-4" />
                <p className="text-gray-400 font-medium text-sm">Loading group...</p>
            </div>
        );
    }

    if (!group) return null;

    return (
        <div className="flex flex-col h-screen bg-gray-100 overflow-hidden" style={{ fontFamily: "'Inter', 'DM Sans', sans-serif" }}>

            {/* ── Top Header ──────────────────────────────────────────────────────── */}
            <header className="bg-white border-b border-gray-200 z-30 shrink-0">
                <div className="flex items-center px-3 sm:px-5 py-3 gap-3">
                    {/* Back button */}
                    <button
                        onClick={goBack}
                        className="w-9 h-9 flex items-center justify-center rounded-full hover:bg-gray-100 text-gray-500 hover:text-gray-800 transition-colors shrink-0"
                        aria-label="Back to groups"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                        </svg>
                    </button>

                    {/* Group avatar */}
                    <div className={`w-10 h-10 rounded-full bg-gradient-to-br ${avatarColor(group.name)} flex items-center justify-center text-white font-bold text-lg shrink-0 shadow`}>
                        {group.name.charAt(0).toUpperCase()}
                    </div>

                    {/* Group info */}
                    <div className="flex-1 min-w-0">
                        <h1 className="font-bold text-gray-900 text-[17px] leading-tight truncate">{group.name}</h1>
                        <div className="flex items-center gap-1.5 mt-0.5">
                            <span className={`w-2 h-2 rounded-full shrink-0 ${isConnected ? 'bg-green-500' : 'bg-yellow-400 animate-pulse'}`} />
                            <span className="text-xs text-gray-500">
                                {isConnected ? 'Online' : 'Connecting...'} &middot; {group.members.length} member{group.members.length !== 1 ? 's' : ''}
                            </span>
                        </div>
                    </div>

                    {/* Stacked member avatars (visible on any screen) */}
                    <div className="hidden sm:flex items-center -space-x-2 mr-2">
                        {group.members.slice(0, 4).map((m) => (
                            <div
                                key={m._id}
                                title={m.name}
                                className={`w-7 h-7 rounded-full bg-gradient-to-br ${avatarColor(m.name)} border-2 border-white flex items-center justify-center text-white text-[10px] font-bold shadow-sm`}
                            >
                                {m.name.charAt(0).toUpperCase()}
                            </div>
                        ))}
                        {group.members.length > 4 && (
                            <div className="w-7 h-7 rounded-full bg-gray-200 border-2 border-white flex items-center justify-center text-gray-500 text-[10px] font-bold shadow-sm">
                                +{group.members.length - 4}
                            </div>
                        )}
                    </div>

                    {/* Three-dot menu */}
                    <button className="w-9 h-9 flex items-center justify-center rounded-full hover:bg-gray-100 text-gray-400 hover:text-gray-600 transition-colors shrink-0">
                        <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20">
                            <path d="M10 6a2 2 0 110-4 2 2 0 010 4zM10 12a2 2 0 110-4 2 2 0 010 4zM10 18a2 2 0 110-4 2 2 0 010 4z" />
                        </svg>
                    </button>
                </div>
            </header>

            {/* ── Main content: chat + optional sidebar ───────────────────────────── */}
            <div className="flex flex-1 overflow-hidden">

                {/* Chat area */}
                <div className="flex flex-col flex-1 min-w-0 bg-[#EFEAE2]">
                    <ChatBox
                        messages={messages}
                        currentUser={user}
                        socket={socketRef.current}
                        groupId={groupId}
                    />
                </div>

                {/* Members sidebar — desktop only */}
                <aside className="hidden lg:flex w-64 xl:w-72 flex-col border-l border-gray-200 bg-white shrink-0">
                    <div className="px-5 py-4 border-b border-gray-100">
                        <h2 className="text-[13px] font-bold text-gray-400 uppercase tracking-wider">
                            Members &mdash; {group.members.length}
                        </h2>
                    </div>
                    <div className="flex-1 overflow-y-auto py-3 px-3 space-y-1">
                        {group.members.map((m) => {
                            const isMe = m._id === user?._id;
                            return (
                                <div key={m._id} className="flex items-center gap-3 px-2 py-2 rounded-xl hover:bg-gray-50 transition-colors group cursor-default">
                                    <div className={`w-9 h-9 rounded-full bg-gradient-to-br ${avatarColor(m.name)} flex items-center justify-center text-white font-bold text-sm shrink-0 shadow-sm group-hover:scale-105 transition-transform`}>
                                        {m.name.charAt(0).toUpperCase()}
                                    </div>
                                    <div className="flex-1 min-w-0">
                                        <p className="text-[14px] font-semibold text-gray-800 truncate leading-tight">
                                            {m.name}
                                            {isMe && (
                                                <span className="ml-1.5 text-[10px] font-bold text-blue-500 bg-blue-50 rounded px-1.5 py-0.5 align-middle">YOU</span>
                                            )}
                                        </p>
                                        <p className="text-[11px] text-gray-400 truncate leading-tight">{m.email}</p>
                                    </div>
                                </div>
                            );
                        })}
                    </div>

                    {/* Created by footer */}
                    <div className="px-5 py-3 border-t border-gray-100 bg-gray-50/70">
                        <p className="text-[11px] text-gray-400">
                            Created by <span className="font-semibold text-gray-600">{group.createdBy?.name || 'Unknown'}</span>
                        </p>
                    </div>
                </aside>
            </div>
        </div>
    );
}
